import{_ as t,c as o,o as a,aj as i}from"./chunks/framework.guNMSiFm.js";const d=JSON.parse('{"title":"Public and Private Blockchains","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configure/modes.md","filePath":"guide/configure/modes.md","lastUpdated":1777621302000}'),s={name:"guide/configure/modes.md"};function n(r,e,c,l,p,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="public-and-private-blockchains" tabindex="-1">Public and Private Blockchains <a class="header-anchor" href="#public-and-private-blockchains" aria-label="Permalink to &quot;Public and Private Blockchains&quot;">​</a></h1><p>Iroha can run in a variety of configurations. As the administrator of your own network, you decide which executor and permission policy determine whether a transaction is accepted.</p><p>The common profiles are <em>private</em> permissioned networks and more open <em>public</em> networks. Both are configured through genesis state and executor policy, not through separate node binaries.</p><p>Below we outline the major differences in these two use cases.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>In a <em>public</em> blockchain, most accounts have the same set of permissions. In a <em>private</em> blockchain, most accounts are assumed not to be able to do anything outside the authority granted to them unless explicitly granted the relevant permission.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Refer to the <a href="/iroha-2-docs/blockchain/permissions.html">dedicated section on permissions</a> for more details.</p></div><h2 id="peers" tabindex="-1">Peers <a class="header-anchor" href="#peers" aria-label="Permalink to &quot;Peers&quot;">​</a></h2><p>In a <em>public</em> blockchain, peer admission is part of chain policy. For a <em>private</em> blockchain, deployments usually pin the trusted peer set in configuration and genesis.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Refer to <a href="./peer-management.html">peer management</a> for more details.</p></div><h2 id="registering-accounts" tabindex="-1">Registering accounts <a class="header-anchor" href="#registering-accounts" aria-label="Permalink to &quot;Registering accounts&quot;">​</a></h2><p>Depending on how you decide to set up your <a href="./genesis.html">genesis block (<code>genesis.json</code>)</a>, the process for registering an account might go one of two ways. To understand why, let&#39;s talk about permission first.</p><p>The selected executor defines which permission checks apply. You can grant the default <a href="/iroha-2-docs/blockchain/permissions.html">permission tokens</a> in genesis to shape a private, administrator-managed network or a more open network. Once those permissions are active, the process of registering accounts is different.</p><p>When it comes to registering accounts, public and private blockchain have the following differences:</p><ul><li><p>In a <em>public</em> blockchain, anyone should be able to register an account<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>. So, in theory, all that you need is a suitable client, a way to generate a private key for a supported algorithm, and permission policy that accepts the registration.</p></li><li><p>In a <em>private</em> blockchain, you can have <em>any</em> process for setting up an account: it could be that the registering instruction has to be submitted by a specific account, or by a smart contract that asks for other details. It could be that in a private blockchain registering new accounts is only possible on specific dates, or limited by a non-mintable (finite) token.</p></li><li><p>In a <em>typical</em> private blockchain, i.e. a blockchain without any unique processes for registering accounts, you need an account to register another account.</p></li></ul><p>The default permission validators cover the typical private blockchain use case.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Public and private modes are policy profiles rather than separate node binaries. Review the executor and genesis permissions you ship before running an open network.</p></div><p>Refer to the section on <a href="/iroha-2-docs/blockchain/instructions.html#un-register">instructions</a> for more details about <code>Register&lt;Account&gt;</code> instructions.</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>Current account IDs are canonical and derive from the account controller. The docs still use &quot;register an account&quot; when describing the <code>Register&lt;Account&gt;</code> instruction. <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',20)])])}const m=t(s,[["render",n]]);export{d as __pageData,m as default};
